import "../Stylesheets/App.css";

export default function Menu() {
  return (
    <div className="navbar">
      <ul className="nav-list">
          <a className="inline-flex text-4xl font-sans font-bold bg-yellow-300 h-fit" href="#">
            Corrida dos DEVs
            <img src="logo.svg" alt="Corrida-dos-devs-logo" className="h-10" />
          </a>
        <li>
        </li>
        <li className="">Ranking</li>
        <li className="">Registro</li>
        <li className="">Login</li>
      </ul>
    </div>
  );
}
